const originalInput = $('Set - Prepare Requirement Context').item.json;
const current = $input.item.json;

let aiOutput =
  current.output ||
  current.text ||
  current.message ||
  current.content ||
  current.data ||
  current;

if (typeof aiOutput === 'string') {
  aiOutput = aiOutput
    .replace(/```json/g, '')
    .replace(/```/g, '')
    .trim();

  try {
    aiOutput = JSON.parse(aiOutput);
  } catch (error) {
    aiOutput = {
      wf01_requirement_analysis: {
        requirement_summary: 'AI output could not be parsed as valid JSON.',
        business_value: '',
        acceptance_criteria_quality: 'incomplete',
        ambiguities: ['Invalid JSON returned by the AI agent.'],
        missing_information: [],
        questions_for_po: ['Review the AI output manually and rerun the requirement analysis.'],
        ready_for_development: false,
        risk_level: 'high',
        human_validation_required: true
      }
    };
  }
}

const analysis = aiOutput.wf01_requirement_analysis || aiOutput;

return {
  json: {
    ...originalInput,
    wf01_requirement_analysis: {
      requirement_summary: analysis.requirement_summary || '',
      business_value: analysis.business_value || '',
      acceptance_criteria_quality: analysis.acceptance_criteria_quality || 'incomplete',
      ambiguities: Array.isArray(analysis.ambiguities) ? analysis.ambiguities : [],
      missing_information: Array.isArray(analysis.missing_information) ? analysis.missing_information : [],
      questions_for_po: Array.isArray(analysis.questions_for_po) ? analysis.questions_for_po : [],
      ready_for_development: Boolean(analysis.ready_for_development),
      risk_level: analysis.risk_level || 'medium',
      human_validation_required: true
    }
  }
};
